INSERT INTO "audit_findings" ("id", "severity", "category", "description", "recommendation", "branch", "status", "assignee", "created_date", "created_by", "updated_at", "timestamp") VALUES
(1, 'HIGH', 'Risk Management', '[AUTO-C17] Loan-to-Deposit Ratio\n\nLDR is 158.4% (loans: 1,500,000 / deposits: 947,253 FCFA). Exceeds 90% regulatory threshold.', 'WHAT: The Loan-to-Deposit Ratio (LDR) measures how much of the bank&#039;s customer deposits have been lent out. A healthy range is typically 30% to 90%.\n\nWHY IT MATTERS: If the LDR is above 90%, the bank may not have enough liquidity to meet withdrawal demands. If below 30%, the bank is not using its deposit base efficiently to generate interest income.\n\nHOW TO FIX: (1) If LDR is above 90%: Reduce new lending, increase deposit mobilization campaigns, or consider securitizing some loans. (2) If LDR is below 30%: Review the lending strategy for growth opportunities, relax qualifying criteria where appropriate, or launch targeted loan products. (3) Set up automated alerts when the ratio approaches 80% or drops below 35%. (4) Review the LDR monthly as part of the Asset-Liability Committee (ALCO) process.\n\nWHO: Chief Risk Officer / Treasury Manager', 'All Branches', 'OPEN', 'Internal Audit System', '2026-04-20', 'Emmanuel Nkoulou', NULL, '2026-04-20 20:37:02'),
(2, 'MEDIUM', 'Transaction Monitoring', '[AUTO-DS03] Off-Hours Transaction Activity\n\n25 transactions were posted outside normal business hours (before 6AM or after 6PM UTC). While some off-hours activity is expected — such as ATM withdrawals, mobile banking transfers, and automated batch processing — a high volume of off-hours transactions warrants review to ensure all activity is legitimate and properly authorized.\n\nMost recent off-hours transactions:\nTXN-20260420-0025 — 45 811 FCFA at 2026-04-20 21:28:40\nTXN-20260420-0024 — 50 000 FCFA at 2026-04-20 21:28:38\nTXN-20260420-0023 — 50 000 FCFA at 2026-04-20 21:28:37\nTXN-20260420-0022 — 50 000 FCFA at 2026-04-20 21:28:36\nTXN-20260420-0021 — 50 000 FCFA at 2026-04-20 21:28:34\nTXN-20260420-0020 — 50 000 FCFA at 2026-04-20 21:28:33\nTXN-20260420-0019 — 50 000 FCFA at 2026-04-20 21:28:32\nTXN-20260420-0018 — 50 000 FCFA at 2026-04-20 21:28:31\nTXN-20260420-0017 — 50 000 FCFA at 2026-04-20 21:28:30\nTXN-20260420-0016 — 50 000 FCFA at 2026-04-20 21:28:28', 'WHAT: A significant number of transactions were posted outside normal business hours.\n\nWHY IT MATTERS: Off-hours transactions can be a sign of unauthorized access, after-hours manipulation of accounts, or automated processing errors. While many off-hours transactions are legitimate (ATMs, mobile banking, batch jobs), the volume detected exceeds typical patterns and should be reviewed.\n\nHOW TO FIX: (1) Review each off-hours transaction to determine the channel (ATM, mobile, branch, batch). (2) For branch-initiated transactions outside business hours, verify the authorization and identify the staff member who posted them. (3) If batch processing explains the volume, document the batch schedule and verify all batch jobs are authorized. (4) Implement channel-specific monitoring so ATM and mobile transactions are separated from staff-initiated ones. (5) Set up alerts for staff-initiated transactions posted outside business hours.\n\nWHO: Branch Operations Manager / IT Security Officer', 'All Branches', 'OPEN', 'Internal Audit System', '2026-04-20', 'Emmanuel Nkoulou', NULL, '2026-04-20 20:37:02'),
(3, 'HIGH', 'Loan Portfolio', '[AUTO-DS02] Suspicious Loan Amount Clustering\n\nMultiple active loans share identical disbursement amounts. While some overlap is normal (e.g., standardized loan products), a high concentration of identical amounts can indicate cloned applications, templated lending without proper risk assessment, or batch processing anomalies.\n\nDetected patterns (top 5): 0 FCFA (3 loans)\n\nTotal pattern groups: 1. This pattern requires investigation to rule out fraud or policy violations.', 'WHAT: Several groups of active loans were disbursed with identical amounts. This clustering pattern is unusual and may indicate cloned loan applications or templated processing.\n\nWHY IT MATTERS: Loan amount clustering can be a sign of fraud — borrowers may be colluding to submit identical applications, or staff may be bypassing individual credit assessments by reusing the same loan template. This exposes the bank to concentration risk and credit losses.\n\nHOW TO FIX: (1) Cross-reference the affected loans for borrower relationships — same employer, same guarantor, same address, or same phone number. (2) Verify each loan went through an independent credit assessment with proper documentation. (3) Check if the disbursement amounts correspond to standard loan products — if not, investigate further. (4) Escalate to the fraud investigation team if borrower collusion is suspected. (5) Review the loan origination process to ensure each application is assessed individually.\n\nWHO: Credit Risk Manager / Fraud Investigation Team', 'All Branches', 'OPEN', 'Internal Audit System', '2026-04-20', 'Emmanuel Nkoulou', NULL, '2026-04-20 21:36:21'),
(4, 'HIGH', 'Compliance', '[AUTO-C06] Customer KYC Completeness\n\n3 customer(s) have incomplete KYC data.', 'WHAT: Some customers have incomplete Know Your Customer (KYC) records. KYC is a regulatory requirement that helps verify customer identity and prevent money laundering.\n\nWHY IT MATTERS: Incomplete KYC is a regulatory violation that can result in fines, sanctions, or license suspension. It also increases the risk of fraud and money laundering.\n\nHOW TO FIX: (1) Generate a list of all customers with incomplete KYC from the Customer Management module. (2) Contact each customer to request missing documents (ID card, proof of address, etc.). (3) Set a deadline — typically 30 days — for customers to provide the required documents. (4) If the deadline passes without compliance, restrict the account (limit transactions or freeze it). (5) Update the account opening process to enforce mandatory KYC fields before activation.\n\nWHO: Compliance Officer / Branch Operations Manager', 'KUMBA', 'CLOSED', 'Internal Audit System', '2026-04-20', 'Emmanuel Nkoulou', NULL, '2026-04-20 22:06:28'),
(5, 'HIGH', 'Risk Management', '[AUTO-C17] Loan-to-Deposit Ratio\n\nLDR is 160% (loans: 8 000 000 / deposits: 5 001 442 FCFA). Exceeds 90% threshold.', 'WHAT: The Loan-to-Deposit Ratio (LDR) measures how much of the bank&#039;s customer deposits have been lent out. A healthy range is typically 30% to 90%.\n\nWHY IT MATTERS: If the LDR is above 90%, the bank may not have enough liquidity to meet withdrawal demands. If below 30%, the bank is not using its deposit base efficiently to generate interest income.\n\nHOW TO FIX: (1) If LDR is above 90%: Reduce new lending, increase deposit mobilization campaigns, or consider securitizing some loans. (2) If LDR is below 30%: Review the lending strategy for growth opportunities, relax qualifying criteria where appropriate, or launch targeted loan products. (3) Set up automated alerts when the ratio approaches 80% or drops below 35%. (4) Review the LDR monthly as part of the Asset-Liability Committee (ALCO) process.\n\nWHO: Chief Risk Officer / Treasury Manager', 'KUMBA', 'CLOSED', 'Internal Audit System', '2026-04-20', 'Emmanuel Nkoulou', NULL, '2026-04-20 22:06:15'),
